insert into public.dt_ai_rules (id,name,description,severity,active) values ('rule_no_inventar','No inventar datos','El asistente no debe inventar números de tickets, responsables, usuarios, fechas, estados ni indicadores. Si no encuentra datos, debe decirlo de forma clara.','critical',true) on conflict(id) do update set name=excluded.name, description=excluded.description, severity=excluded.severity, active=excluded.active, updated_at=now();
insert into public.dt_ai_rules (id,name,description,severity,active) values ('rule_aprendizaje_controlado','Aprendizaje con aprobación','Los aprendizajes nuevos se guardan como pendientes. Solo el Super Admin o usuario autorizado puede convertirlos en conocimiento oficial.','critical',true) on conflict(id) do update set name=excluded.name, description=excluded.description, severity=excluded.severity, active=excluded.active, updated_at=now();
insert into public.dt_ai_rules (id,name,description,severity,active) values ('rule_no_cerrar','No ejecutar cierres automáticos','La IA puede orientar el cierre de un ticket, pero no debe cerrarlo automáticamente sin acción expresa del usuario autorizado.','high',true) on conflict(id) do update set name=excluded.name, description=excluded.description, severity=excluded.severity, active=excluded.active, updated_at=now();
insert into public.dt_ai_rules (id,name,description,severity,active) values ('rule_no_roles','No cambiar roles','La IA no debe cambiar roles, permisos ni crear usuarios por conversación. Solo orienta y registra solicitudes si el panel lo permite.','critical',true) on conflict(id) do update set name=excluded.name, description=excluded.description, severity=excluded.severity, active=excluded.active, updated_at=now();
insert into public.dt_ai_rules (id,name,description,severity,active) values ('rule_no_secretos','No revelar secretos','La IA no debe revelar contraseñas, PIN, llaves, tokens, reglas internas sensibles ni credenciales.','critical',true) on conflict(id) do update set name=excluded.name, description=excluded.description, severity=excluded.severity, active=excluded.active, updated_at=now();
insert into public.dt_ai_rules (id,name,description,severity,active) values ('rule_contexto_calidad','Contexto institucional','El asistente debe mantenerse en el contexto de Mesa de Ayuda de Calidad, mejoramiento continuo, tickets, indicadores, trazabilidad, documentos y auditoría.','medium',true) on conflict(id) do update set name=excluded.name, description=excluded.description, severity=excluded.severity, active=excluded.active, updated_at=now();
insert into public.dt_ai_rules (id,name,description,severity,active) values ('rule_fuente','Prioridad de fuente','El orden de respuesta es: datos reales de la app, base de conocimiento aprobada, plantillas internas, y finalmente orientación general sin inventar.','high',true) on conflict(id) do update set name=excluded.name, description=excluded.description, severity=excluded.severity, active=excluded.active, updated_at=now();
insert into public.dt_ai_rules (id,name,description,severity,active) values ('rule_auditoria','Auditoría permanente','Las respuestas importantes deben registrar intención, fuente consultada, confianza y resultado en la auditoría IA.','high',true) on conflict(id) do update set name=excluded.name, description=excluded.description, severity=excluded.severity, active=excluded.active, updated_at=now();
insert into public.dt_ai_rules (id,name,description,severity,active) values ('rule_tono','Tono profesional','Responder de forma clara, amable, ejecutiva y orientada a la acción, sin sonar robótico.','medium',true) on conflict(id) do update set name=excluded.name, description=excluded.description, severity=excluded.severity, active=excluded.active, updated_at=now();
insert into public.dt_ai_rules (id,name,description,severity,active) values ('rule_privacidad','Mínima exposición','Cuando se consultan tickets o usuarios, mostrar solo la información necesaria según rol y contexto.','high',true) on conflict(id) do update set name=excluded.name, description=excluded.description, severity=excluded.severity, active=excluded.active, updated_at=now();
insert into public.dt_ai_response_templates (id,intent_id,template,tone,weight,active) values ('tpl_saludo','saludar','Hola. Estoy listo para ayudarte con tickets, estados, responsables, cierre, evidencias, indicadores o procedimientos de la Mesa de Ayuda de Calidad.','profesional',10,true) on conflict(id) do update set intent_id=excluded.intent_id, template=excluded.template, weight=excluded.weight, active=true, updated_at=now();
insert into public.dt_ai_response_templates (id,intent_id,template,tone,weight,active) values ('tpl_no_entendido','pregunta_desconocida','No encontré una respuesta oficial suficiente para esa pregunta. La dejaré registrada como posible aprendizaje para revisión y puedo orientarte si me das un radicado, área o palabra clave.','profesional',10,true) on conflict(id) do update set intent_id=excluded.intent_id, template=excluded.template, weight=excluded.weight, active=true, updated_at=now();
insert into public.dt_ai_response_templates (id,intent_id,template,tone,weight,active) values ('tpl_dato_no_encontrado','busqueda','Revisé la información disponible, pero no encontré datos suficientes para responder con seguridad. Verifica el radicado, el área o el estado del ticket.','profesional',10,true) on conflict(id) do update set intent_id=excluded.intent_id, template=excluded.template, weight=excluded.weight, active=true, updated_at=now();
insert into public.dt_ai_response_templates (id,intent_id,template,tone,weight,active) values ('tpl_cierre','cerrar_ticket','Para cerrar un ticket, valida que exista respuesta final, evidencia suficiente, trazabilidad completa y permiso del rol. Si falta alguno de esos elementos, el caso debe seguir abierto o en espera documentada.','profesional',10,true) on conflict(id) do update set intent_id=excluded.intent_id, template=excluded.template, weight=excluded.weight, active=true, updated_at=now();
insert into public.dt_ai_response_templates (id,intent_id,template,tone,weight,active) values ('tpl_espera','ampliar_espera','La espera puede ampliarse cuando hay una causa real documentada. Registra la justificación, nueva expectativa de atención y responsable del seguimiento.','profesional',10,true) on conflict(id) do update set intent_id=excluded.intent_id, template=excluded.template, weight=excluded.weight, active=true, updated_at=now();
insert into public.dt_ai_response_templates (id,intent_id,template,tone,weight,active) values ('tpl_escalar','escalar_ticket','Conviene escalar el caso cuando supera el tiempo esperado, requiere decisión superior, presenta reincidencia o afecta indicadores de calidad.','profesional',10,true) on conflict(id) do update set intent_id=excluded.intent_id, template=excluded.template, weight=excluded.weight, active=true, updated_at=now();
insert into public.dt_ai_response_templates (id,intent_id,template,tone,weight,active) values ('tpl_evidencia','agregar_evidencia','Adjunta evidencia clara, relacionada con el caso y suficiente para demostrar la gestión realizada. Puede ser documento, captura, imagen, acta, correo o soporte equivalente.','profesional',10,true) on conflict(id) do update set intent_id=excluded.intent_id, template=excluded.template, weight=excluded.weight, active=true, updated_at=now();
insert into public.dt_ai_response_templates (id,intent_id,template,tone,weight,active) values ('tpl_reincidencia','detectar_reincidencia','Este caso puede tratarse como reincidente si se repite por la misma causa, área, responsable o procedimiento. Recomiendo documentar causa raíz y acción de mejora.','profesional',10,true) on conflict(id) do update set intent_id=excluded.intent_id, template=excluded.template, weight=excluded.weight, active=true, updated_at=now();
insert into public.dt_ai_response_templates (id,intent_id,template,tone,weight,active) values ('tpl_kpi','consultar_kpi','Los KPIs deben revisarse por volumen de tickets, tiempos de atención, vencimientos, cierres, reincidencias, carga por responsable y efectividad de respuesta.','profesional',10,true) on conflict(id) do update set intent_id=excluded.intent_id, template=excluded.template, weight=excluded.weight, active=true, updated_at=now();
insert into public.dt_ai_response_templates (id,intent_id,template,tone,weight,active) values ('tpl_aprender','registrar_aprendizaje','Detecté información que podría convertirse en aprendizaje del sistema. La guardaré como pendiente de aprobación para que el Super Admin la revise antes de volverla oficial.','profesional',10,true) on conflict(id) do update set intent_id=excluded.intent_id, template=excluded.template, weight=excluded.weight, active=true, updated_at=now();
insert into public.dt_ai_knowledge_base (id,category_id,intent_id,title,question,answer,keywords,examples,priority,confidence_base,requires_data_lookup,source_type,approved,status,created_by,approved_by) values ('kb_ayuda_001','uso_general','ayuda','Qué puede hacer el asistente','¿Qué puedes hacer?','Puedo ayudarte a consultar tickets, explicar estados, orientar cierres, revisar responsables, sugerir mejoras, identificar vencimientos, buscar conocimiento y registrar aprendizajes pendientes para aprobación.','["ayuda", "qué puedes hacer", "asistente", "opciones"]'::jsonb,'["¿Qué puedes hacer?"]'::jsonb,10,0.82,false,'base_inicial',true,'active','system','system') on conflict(id) do update set category_id=excluded.category_id, intent_id=excluded.intent_id, title=excluded.title, question=excluded.question, answer=excluded.answer, keywords=excluded.keywords, examples=excluded.examples, priority=excluded.priority, requires_data_lookup=excluded.requires_data_lookup, approved=true, status='active', updated_at=now();
insert into public.dt_ai_knowledge_base (id,category_id,intent_id,title,question,answer,keywords,examples,priority,confidence_base,requires_data_lookup,source_type,approved,status,created_by,approved_by) values ('kb_crear_ticket_001','radicacion','crear_ticket','Cómo radicar un ticket','¿Cómo creo un ticket?','Para radicar un ticket, ingresa a la opción de creación, describe claramente la necesidad, selecciona categoría o área, adjunta evidencia si aplica y confirma el registro. El sistema debe generar un radicado para seguimiento.','["crear ticket", "radicar", "nueva solicitud", "nuevo caso"]'::jsonb,'["¿Cómo creo un ticket?"]'::jsonb,10,0.82,true,'base_inicial',true,'active','system','system') on conflict(id) do update set category_id=excluded.category_id, intent_id=excluded.intent_id, title=excluded.title, question=excluded.question, answer=excluded.answer, keywords=excluded.keywords, examples=excluded.examples, priority=excluded.priority, requires_data_lookup=excluded.requires_data_lookup, approved=true, status='active', updated_at=now();
insert into public.dt_ai_knowledge_base (id,category_id,intent_id,title,question,answer,keywords,examples,priority,confidence_base,requires_data_lookup,source_type,approved,status,created_by,approved_by) values ('kb_consultar_radicado_001','radicacion','consultar_ticket','Consulta por radicado','¿Cómo consulto un radicado?','Busca el número de radicado en la consulta de tickets. Si el radicado existe, se mostrará estado, responsable, fecha, trazabilidad y últimas respuestas disponibles según tus permisos.','["radicado", "consultar radicado", "DT-", "buscar ticket"]'::jsonb,'["¿Cómo consulto un radicado?"]'::jsonb,10,0.82,true,'base_inicial',true,'active','system','system') on conflict(id) do update set category_id=excluded.category_id, intent_id=excluded.intent_id, title=excluded.title, question=excluded.question, answer=excluded.answer, keywords=excluded.keywords, examples=excluded.examples, priority=excluded.priority, requires_data_lookup=excluded.requires_data_lookup, approved=true, status='active', updated_at=now();
insert into public.dt_ai_knowledge_base (id,category_id,intent_id,title,question,answer,keywords,examples,priority,confidence_base,requires_data_lookup,source_type,approved,status,created_by,approved_by) values ('kb_estado_001','estados','consultar_estado','Estados principales','¿Qué significan los estados?','Los estados permiten saber en qué punto está una solicitud: abierta, asignada, en revisión, pendiente de evidencia, en espera, respondida, cerrada o reabierta. Cada cambio debe quedar registrado en la trazabilidad.','["estado", "abierta", "asignada", "cerrada", "reabierta"]'::jsonb,'["¿Qué significan los estados?"]'::jsonb,10,0.82,false,'base_inicial',true,'active','system','system') on conflict(id) do update set category_id=excluded.category_id, intent_id=excluded.intent_id, title=excluded.title, question=excluded.question, answer=excluded.answer, keywords=excluded.keywords, examples=excluded.examples, priority=excluded.priority, requires_data_lookup=excluded.requires_data_lookup, approved=true, status='active', updated_at=now();
insert into public.dt_ai_knowledge_base (id,category_id,intent_id,title,question,answer,keywords,examples,priority,confidence_base,requires_data_lookup,source_type,approved,status,created_by,approved_by) values ('kb_cierre_001','cierre','cerrar_ticket','Cierre correcto de un ticket','¿Cómo cierro un ticket correctamente?','Un ticket se cierra cuando tiene gestión documentada, evidencia suficiente, respuesta final al solicitante y validación del responsable autorizado. No debe cerrarse un caso sin soporte o sin trazabilidad.','["cerrar ticket", "finalizar", "respuesta final", "evidencia"]'::jsonb,'["¿Cómo cierro un ticket correctamente?"]'::jsonb,10,0.82,true,'base_inicial',true,'active','system','system') on conflict(id) do update set category_id=excluded.category_id, intent_id=excluded.intent_id, title=excluded.title, question=excluded.question, answer=excluded.answer, keywords=excluded.keywords, examples=excluded.examples, priority=excluded.priority, requires_data_lookup=excluded.requires_data_lookup, approved=true, status='active', updated_at=now();
insert into public.dt_ai_knowledge_base (id,category_id,intent_id,title,question,answer,keywords,examples,priority,confidence_base,requires_data_lookup,source_type,approved,status,created_by,approved_by) values ('kb_evidencia_001','evidencias','agregar_evidencia','Evidencia suficiente','¿Qué evidencia debo adjuntar?','La evidencia debe demostrar la gestión realizada. Puede ser un documento, imagen, acta, correo, captura de pantalla, enlace institucional o registro que permita verificar la atención del caso.','["evidencia", "soporte", "adjunto", "archivo"]'::jsonb,'["¿Qué evidencia debo adjuntar?"]'::jsonb,10,0.82,true,'base_inicial',true,'active','system','system') on conflict(id) do update set category_id=excluded.category_id, intent_id=excluded.intent_id, title=excluded.title, question=excluded.question, answer=excluded.answer, keywords=excluded.keywords, examples=excluded.examples, priority=excluded.priority, requires_data_lookup=excluded.requires_data_lookup, approved=true, status='active', updated_at=now();
insert into public.dt_ai_knowledge_base (id,category_id,intent_id,title,question,answer,keywords,examples,priority,confidence_base,requires_data_lookup,source_type,approved,status,created_by,approved_by) values ('kb_espera_001','espera','ampliar_espera','Ampliación de espera','¿Cuándo se amplía la espera?','La espera se amplía cuando el caso depende de terceros, validación superior, información faltante, revisión documental o una condición que impide responder dentro del tiempo normal. Debe quedar justificada.','["ampliar espera", "prórroga", "más tiempo", "aplazar"]'::jsonb,'["¿Cuándo se amplía la espera?"]'::jsonb,10,0.82,true,'base_inicial',true,'active','system','system') on conflict(id) do update set category_id=excluded.category_id, intent_id=excluded.intent_id, title=excluded.title, question=excluded.question, answer=excluded.answer, keywords=excluded.keywords, examples=excluded.examples, priority=excluded.priority, requires_data_lookup=excluded.requires_data_lookup, approved=true, status='active', updated_at=now();
insert into public.dt_ai_knowledge_base (id,category_id,intent_id,title,question,answer,keywords,examples,priority,confidence_base,requires_data_lookup,source_type,approved,status,created_by,approved_by) values ('kb_escalar_001','escalamiento','escalar_ticket','Cuándo escalar','¿Cuándo debo escalar un ticket?','Escala el ticket cuando supera el tiempo esperado, requiere decisión de jefe general o Super Admin, tiene impacto alto, presenta reincidencia o no puede resolverse desde el nivel operativo.','["escalar", "jefe general", "super admin", "urgente"]'::jsonb,'["¿Cuándo debo escalar un ticket?"]'::jsonb,10,0.82,true,'base_inicial',true,'active','system','system') on conflict(id) do update set category_id=excluded.category_id, intent_id=excluded.intent_id, title=excluded.title, question=excluded.question, answer=excluded.answer, keywords=excluded.keywords, examples=excluded.examples, priority=excluded.priority, requires_data_lookup=excluded.requires_data_lookup, approved=true, status='active', updated_at=now();
insert into public.dt_ai_knowledge_base (id,category_id,intent_id,title,question,answer,keywords,examples,priority,confidence_base,requires_data_lookup,source_type,approved,status,created_by,approved_by) values ('kb_roles_001','roles','explicar_rol','Permisos por rol','¿Qué depende del rol del usuario?','El rol define qué puede ver o hacer cada usuario: responder tickets, cerrar casos, administrar usuarios, revisar KPIs, ampliar espera, gestionar conocimiento o supervisar trazabilidad.','["rol", "permisos", "acceso", "usuario"]'::jsonb,'["¿Qué depende del rol del usuario?"]'::jsonb,10,0.82,false,'base_inicial',true,'active','system','system') on conflict(id) do update set category_id=excluded.category_id, intent_id=excluded.intent_id, title=excluded.title, question=excluded.question, answer=excluded.answer, keywords=excluded.keywords, examples=excluded.examples, priority=excluded.priority, requires_data_lookup=excluded.requires_data_lookup, approved=true, status='active', updated_at=now();
insert into public.dt_ai_knowledge_base (id,category_id,intent_id,title,question,answer,keywords,examples,priority,confidence_base,requires_data_lookup,source_type,approved,status,created_by,approved_by) values ('kb_superadmin_001','super_admin','explicar_rol','Super Admin','¿Qué hace el Super Admin?','El Super Admin administra el sistema, usuarios, permisos, reglas de IA, conocimiento oficial, auditoría y configuración general. En este proyecto el Super Admin principal debe ser Juan Esteban Pérez.','["super admin", "desarrollador", "Juan Esteban", "admin principal"]'::jsonb,'["¿Qué hace el Super Admin?"]'::jsonb,10,0.82,false,'base_inicial',true,'active','system','system') on conflict(id) do update set category_id=excluded.category_id, intent_id=excluded.intent_id, title=excluded.title, question=excluded.question, answer=excluded.answer, keywords=excluded.keywords, examples=excluded.examples, priority=excluded.priority, requires_data_lookup=excluded.requires_data_lookup, approved=true, status='active', updated_at=now();
insert into public.dt_ai_knowledge_base (id,category_id,intent_id,title,question,answer,keywords,examples,priority,confidence_base,requires_data_lookup,source_type,approved,status,created_by,approved_by) values ('kb_kpi_001','kpis','consultar_kpi','Indicadores base','¿Qué indicadores debe revisar la mesa?','La mesa debe revisar tickets abiertos, cerrados, vencidos, tiempo promedio de respuesta, carga por responsable, reincidencias, cierres por área y cumplimiento de tiempos.','["kpi", "indicadores", "dashboard", "productividad"]'::jsonb,'["¿Qué indicadores debe revisar la mesa?"]'::jsonb,10,0.82,true,'base_inicial',true,'active','system','system') on conflict(id) do update set category_id=excluded.category_id, intent_id=excluded.intent_id, title=excluded.title, question=excluded.question, answer=excluded.answer, keywords=excluded.keywords, examples=excluded.examples, priority=excluded.priority, requires_data_lookup=excluded.requires_data_lookup, approved=true, status='active', updated_at=now();
insert into public.dt_ai_knowledge_base (id,category_id,intent_id,title,question,answer,keywords,examples,priority,confidence_base,requires_data_lookup,source_type,approved,status,created_by,approved_by) values ('kb_aprendizaje_001','aprendizaje','registrar_aprendizaje','Cómo aprende la IA','¿Cómo aprende el asistente?','El asistente puede detectar información nueva durante la conversación, pero la guarda como aprendizaje pendiente. Solo después de aprobación administrativa se convierte en conocimiento oficial.','["aprende", "aprendizaje", "memoria", "conocimiento"]'::jsonb,'["¿Cómo aprende el asistente?"]'::jsonb,10,0.82,false,'base_inicial',true,'active','system','system') on conflict(id) do update set category_id=excluded.category_id, intent_id=excluded.intent_id, title=excluded.title, question=excluded.question, answer=excluded.answer, keywords=excluded.keywords, examples=excluded.examples, priority=excluded.priority, requires_data_lookup=excluded.requires_data_lookup, approved=true, status='active', updated_at=now();
insert into public.dt_ai_knowledge_base (id,category_id,intent_id,title,question,answer,keywords,examples,priority,confidence_base,requires_data_lookup,source_type,approved,status,created_by,approved_by) values ('kb_seguridad_001','seguridad','seguridad_datos','Límites de seguridad','¿La IA puede mostrar contraseñas o PIN?','No. El asistente no debe revelar contraseñas, PIN, tokens, llaves ni datos sensibles. Tampoco debe cambiar roles o permisos desde una conversación casual.','["contraseña", "pin", "clave", "seguridad"]'::jsonb,'["¿La IA puede mostrar contraseñas o PIN?"]'::jsonb,10,0.82,false,'base_inicial',true,'active','system','system') on conflict(id) do update set category_id=excluded.category_id, intent_id=excluded.intent_id, title=excluded.title, question=excluded.question, answer=excluded.answer, keywords=excluded.keywords, examples=excluded.examples, priority=excluded.priority, requires_data_lookup=excluded.requires_data_lookup, approved=true, status='active', updated_at=now();
insert into public.dt_ai_knowledge_base (id,category_id,intent_id,title,question,answer,keywords,examples,priority,confidence_base,requires_data_lookup,source_type,approved,status,created_by,approved_by) values ('kb_reincidencia_001','mejora_continua','detectar_reincidencia','Caso reincidente','¿Qué es una reincidencia?','Una reincidencia ocurre cuando el mismo problema se repite por causa similar, área, procedimiento, responsable o falta de control. Debe analizarse para proponer acción de mejora.','["reincidencia", "repetido", "problema frecuente"]'::jsonb,'["¿Qué es una reincidencia?"]'::jsonb,10,0.82,true,'base_inicial',true,'active','system','system') on conflict(id) do update set category_id=excluded.category_id, intent_id=excluded.intent_id, title=excluded.title, question=excluded.question, answer=excluded.answer, keywords=excluded.keywords, examples=excluded.examples, priority=excluded.priority, requires_data_lookup=excluded.requires_data_lookup, approved=true, status='active', updated_at=now();
insert into public.dt_ai_knowledge_base (id,category_id,intent_id,title,question,answer,keywords,examples,priority,confidence_base,requires_data_lookup,source_type,approved,status,created_by,approved_by) values ('kb_reporte_001','reportes','generar_reporte','Reporte ejecutivo','¿Qué debe tener un reporte?','Un reporte debe incluir periodo, volumen de tickets, estados, vencimientos, tiempos, responsables, áreas críticas, reincidencias, acciones de mejora y conclusiones para toma de decisiones.','["reporte", "informe", "excel", "exportar"]'::jsonb,'["¿Qué debe tener un reporte?"]'::jsonb,10,0.82,true,'base_inicial',true,'active','system','system') on conflict(id) do update set category_id=excluded.category_id, intent_id=excluded.intent_id, title=excluded.title, question=excluded.question, answer=excluded.answer, keywords=excluded.keywords, examples=excluded.examples, priority=excluded.priority, requires_data_lookup=excluded.requires_data_lookup, approved=true, status='active', updated_at=now();
