insert into public.dt_ai_knowledge_base (id,category_id,intent_id,title,question,answer,keywords,examples,priority,confidence_base,requires_data_lookup,source_type,approved,status,created_by,approved_by) values ('kb_conv_002','conversacion','agradecer','Agradecimiento','Gracias','Con gusto. Dejo la orientación lista y, si necesitas, también puedo ayudarte a ubicar el ticket o convertir el caso en una acción de mejora.','["gracias", "muchas gracias"]'::jsonb,'["Gracias"]'::jsonb,8,0.82,false,'base_inicial',true,'active','system','system') on conflict(id) do update set category_id=excluded.category_id, intent_id=excluded.intent_id, title=excluded.title, question=excluded.question, answer=excluded.answer, keywords=excluded.keywords, examples=excluded.examples, priority=excluded.priority, requires_data_lookup=excluded.requires_data_lookup, approved=true, status='active', updated_at=now();
