
-- ===============================================================
-- MESA DE AYUDA DE CALIDAD - IA NIVEL 1 SIN API PAGA
-- Motor conversacional, base de conocimiento, aprendizaje controlado
-- Diseñado para GitHub Pages + Supabase.
-- No incluye credenciales, tokens ni contraseñas.
-- ===============================================================

begin;

-- ---------- TABLAS BASE IA ----------
create table if not exists public.dt_ai_categories (
  id text primary key,
  name text not null,
  description text,
  sort_order int default 0,
  active boolean default true,
  created_at timestamptz default now(),
  updated_at timestamptz default now()
);

create table if not exists public.dt_ai_intents (
  id text primary key,
  category_id text references public.dt_ai_categories(id) on delete set null,
  name text not null,
  description text,
  requires_data_lookup boolean default false,
  active boolean default true,
  created_at timestamptz default now(),
  updated_at timestamptz default now()
);

create table if not exists public.dt_ai_synonyms (
  id bigserial primary key,
  intent_id text references public.dt_ai_intents(id) on delete cascade,
  term text not null,
  weight numeric default 1.0,
  active boolean default true,
  created_at timestamptz default now()
);

create table if not exists public.dt_ai_response_templates (
  id text primary key,
  intent_id text references public.dt_ai_intents(id) on delete set null,
  template text not null,
  tone text default 'profesional',
  weight int default 1,
  active boolean default true,
  created_at timestamptz default now(),
  updated_at timestamptz default now()
);

create table if not exists public.dt_ai_knowledge_base (
  id text primary key,
  category_id text references public.dt_ai_categories(id) on delete set null,
  intent_id text references public.dt_ai_intents(id) on delete set null,
  title text not null,
  question text,
  answer text not null,
  keywords jsonb default '[]'::jsonb,
  examples jsonb default '[]'::jsonb,
  required_role_keys jsonb default '[]'::jsonb,
  allowed_area_keys jsonb default '[]'::jsonb,
  priority int default 5,
  confidence_base numeric default 0.75,
  requires_data_lookup boolean default false,
  source_type text default 'base_inicial',
  approved boolean default true,
  status text default 'active',
  created_by text default 'system',
  approved_by text,
  created_at timestamptz default now(),
  updated_at timestamptz default now()
);

create table if not exists public.dt_ai_rules (
  id text primary key,
  name text not null,
  description text not null,
  severity text default 'medium',
  active boolean default true,
  created_at timestamptz default now(),
  updated_at timestamptz default now()
);

create table if not exists public.dt_ai_conversations (
  id uuid primary key default gen_random_uuid(),
  user_id text,
  user_name text,
  role_key text,
  area text,
  title text,
  context jsonb default '{}'::jsonb,
  status text default 'active',
  created_at timestamptz default now(),
  updated_at timestamptz default now()
);

create table if not exists public.dt_ai_messages (
  id uuid primary key default gen_random_uuid(),
  conversation_id uuid references public.dt_ai_conversations(id) on delete cascade,
  sender text not null check (sender in ('user','assistant','system')),
  message text not null,
  intent_id text,
  confidence numeric,
  sources jsonb default '[]'::jsonb,
  metadata jsonb default '{}'::jsonb,
  created_at timestamptz default now()
);

create table if not exists public.dt_ai_memory (
  id uuid primary key default gen_random_uuid(),
  user_id text,
  conversation_id uuid references public.dt_ai_conversations(id) on delete cascade,
  memory_type text default 'conversation',
  key text,
  value text not null,
  weight numeric default 1.0,
  expires_at timestamptz,
  status text default 'active',
  created_at timestamptz default now(),
  updated_at timestamptz default now()
);

create table if not exists public.dt_ai_learning_queue (
  id uuid primary key default gen_random_uuid(),
  detected_from text default 'conversation',
  conversation_id uuid references public.dt_ai_conversations(id) on delete set null,
  user_id text,
  suggested_title text,
  suggested_knowledge text not null,
  suggested_category_id text references public.dt_ai_categories(id) on delete set null,
  suggested_intent_id text references public.dt_ai_intents(id) on delete set null,
  keywords jsonb default '[]'::jsonb,
  confidence numeric default 0.5,
  status text default 'pending_review',
  reviewed_by text,
  reviewed_at timestamptz,
  decision_notes text,
  created_at timestamptz default now(),
  updated_at timestamptz default now()
);

create table if not exists public.dt_ai_unanswered_questions (
  id uuid primary key default gen_random_uuid(),
  conversation_id uuid references public.dt_ai_conversations(id) on delete set null,
  user_id text,
  question text not null,
  detected_intent_id text,
  best_score numeric default 0,
  status text default 'open',
  created_at timestamptz default now(),
  resolved_at timestamptz,
  resolved_by text
);

create table if not exists public.dt_ai_feedback (
  id uuid primary key default gen_random_uuid(),
  message_id uuid references public.dt_ai_messages(id) on delete cascade,
  user_id text,
  rating int check (rating between 1 and 5),
  comment text,
  created_at timestamptz default now()
);

create table if not exists public.dt_ai_audit_log (
  id uuid primary key default gen_random_uuid(),
  actor_user_id text,
  actor_name text,
  action text not null,
  entity_type text,
  entity_id text,
  intent_id text,
  confidence numeric,
  details jsonb default '{}'::jsonb,
  created_at timestamptz default now()
);

create table if not exists public.dt_ai_action_registry (
  id text primary key,
  name text not null,
  description text,
  intent_id text references public.dt_ai_intents(id) on delete set null,
  query_target text,
  allowed_role_keys jsonb default '[]'::jsonb,
  requires_confirmation boolean default false,
  active boolean default true,
  created_at timestamptz default now()
);

create table if not exists public.dt_ai_entity_aliases (
  id bigserial primary key,
  entity_type text not null,
  canonical_value text not null,
  alias text not null,
  active boolean default true,
  created_at timestamptz default now()
);

-- ---------- ÍNDICES ----------
create index if not exists idx_dt_ai_kb_status_category on public.dt_ai_knowledge_base(status, category_id);
create index if not exists idx_dt_ai_kb_intent on public.dt_ai_knowledge_base(intent_id);
create index if not exists idx_dt_ai_kb_keywords on public.dt_ai_knowledge_base using gin(keywords);
create index if not exists idx_dt_ai_messages_conversation on public.dt_ai_messages(conversation_id, created_at);
create index if not exists idx_dt_ai_learning_status on public.dt_ai_learning_queue(status, created_at desc);
create index if not exists idx_dt_ai_audit_created on public.dt_ai_audit_log(created_at desc);

-- ---------- FUNCIÓN DE BÚSQUEDA SIN VECTOR NI API PAGA ----------
create or replace function public.dt_ai_search_knowledge(p_query text, p_intent text default null, p_limit int default 8)
returns table (
  id text,
  title text,
  question text,
  answer text,
  category_id text,
  intent_id text,
  priority int,
  score numeric,
  keywords jsonb
)
language sql
stable
as $$
  with q as (
    select lower(coalesce(p_query,'')) as txt
  ), kb as (
    select k.*,
      lower(coalesce(k.title,'') || ' ' || coalesce(k.question,'') || ' ' || coalesce(k.answer,'') || ' ' || coalesce(k.keywords::text,'')) as haystack
    from public.dt_ai_knowledge_base k
    where k.status = 'active'
      and k.approved = true
      and (p_intent is null or k.intent_id = p_intent)
  )
  select
    kb.id,
    kb.title,
    kb.question,
    kb.answer,
    kb.category_id,
    kb.intent_id,
    kb.priority,
    (
      case when kb.haystack like '%' || q.txt || '%' then 5 else 0 end +
      case when lower(coalesce(kb.question,'')) like '%' || q.txt || '%' then 4 else 0 end +
      case when lower(coalesce(kb.title,'')) like '%' || q.txt || '%' then 3 else 0 end +
      case when lower(coalesce(kb.keywords::text,'')) like '%' || q.txt || '%' then 3 else 0 end +
      kb.priority * 0.10
    )::numeric as score,
    kb.keywords
  from kb, q
  where length(q.txt) >= 2
    and (
      kb.haystack like '%' || q.txt || '%'
      or exists (
        select 1
        from regexp_split_to_table(q.txt, '\s+') term
        where length(term) > 2 and kb.haystack like '%' || term || '%'
      )
    )
  order by score desc, priority desc, updated_at desc
  limit greatest(1, coalesce(p_limit,8));
$$;

-- ---------- ACCIONES LÓGICAS DISPONIBLES ----------
on conflict (id) do update set name=excluded.name, description=excluded.description, intent_id=excluded.intent_id, query_target=excluded.query_target, active=excluded.active;

