-- ---------- SEMILLA: BASE DE CONOCIMIENTO INICIAL ROBUSTA ----------


-- ---------- VISTA RESUMEN PARA PANEL ----------
create or replace view public.v_dt_ai_knowledge_panel as
select
  k.id,
  k.title,
  k.question,
  k.category_id,
  c.name as category_name,
  k.intent_id,
  i.name as intent_name,
  k.priority,
  k.requires_data_lookup,
  k.status,
  k.approved,
  k.updated_at
from public.dt_ai_knowledge_base k
left join public.dt_ai_categories c on c.id = k.category_id
left join public.dt_ai_intents i on i.id = k.intent_id;

commit;
